    public static bool TryGet(string preset, out AircraftControlDefinition control) =>
        Controls.TryGetValue(preset, out control!);

    public static AircraftControlDefinition GetRequired(string preset)
    {
        if (!TryGet(preset, out var control))
        {
            throw new InvalidOperationException($"Documented iniBuilds A320 preset not found: {preset}");
        }

        return control;
    }

    public static int Count => Controls.Count;
